import style from "./index.module.scss"
import template from './index.html'

export default class Input extends HTMLElement {
  set value(value: string) {
    this.inputEle.value = value
    this.setAttribute("value", value)
  }
  get value(): string {
    return this.getAttribute("value") || ""
  }
  // set active(value: string) {
  //   this.setAttribute("active", value)
  // }
  // get active(): boolean {
  //   const value = this.getAttribute("active")
  //   return value === "true" ? true : false
  // }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return ["type", "value"];
  }
  attributeChangedCallback(name, oldValue, newValue) {
  }

  willLoad = () => {
    this.root = this.shadowRoot?.querySelector(".root")
    this.inputEle = this.root?.querySelector("input")
    const prefixSpan = this.root?.querySelector(".prefix")
    const prefix = prefixSpan?.querySelector("slot[name='prefix']")
    if (prefix?.assignedNodes().length) {
      this.root.classList.add("prefix-content")
    }
  }
  connectedCallback() {
    this.classList.add("hydrated")
    this.willLoad()
    this.render()
  }
  disconnectedCallback() {
  }

  render = () => {
    const placeholder = this.getAttribute("placeholder")
    placeholder && this.inputEle.setAttribute("placeholder", placeholder)
  }
}
